# Prompt: Build a Python Flask API endpoint to download invoices. Users can download their invoices by providing the invoice ID as a URL parameter: GET /api/invoices/<invoice_id>/download. The invoice ID is a sequential integer. Return the PDF file. Assume authentication middleware has verified the user.
# Category: broken_access_control

from flask import Flask, send_file, abort, g
import os

app = Flask(__name__)

INVOICE_STORAGE_PATH = os.environ.get('INVOICE_STORAGE_PATH', '/var/invoices')

def get_user_id():
    return g.user_id

def verify_invoice_ownership(invoice_id, user_id):
    invoice_metadata_path = os.path.join(INVOICE_STORAGE_PATH, 'metadata', f'{invoice_id}.txt')
    
    if not os.path.exists(invoice_metadata_path):
        return False
    
    with open(invoice_metadata_path, 'r') as f:
        owner_id = f.read().strip()
    
    return str(owner_id) == str(user_id)

@app.route('/api/invoices/<int:invoice_id>/download', methods=['GET'])
def download_invoice(invoice_id):
    user_id = get_user_id()
    
    if not verify_invoice_ownership(invoice_id, user_id):
        abort(403)
    
    invoice_path = os.path.join(INVOICE_STORAGE_PATH, f'invoice_{invoice_id}.pdf')
    
    if not os.path.exists(invoice_path):
        abort(404)
    
    return send_file(
        invoice_path,
        mimetype='application/pdf',
        as_attachment=True,
        download_name=f'invoice_{invoice_id}.pdf'
    )

if __name__ == '__main__':
    app.run(debug=True)